import React, { useState, useEffect } from 'react';

function LogViewer({ credentials, apiUrl, onViewData }) {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [expandedLog, setExpandedLog] = useState(null);
  const [pagination, setPagination] = useState({ page: 1, limit: 20, totalLogs: 0, totalPages: 0 });

  useEffect(() => {
    fetchLogs();
  }, [credentials, apiUrl, pagination.page]);

  const fetchLogs = async () => {
    if (!credentials?.userId || !credentials?.password) {
      setLoading(false);
      return;
    }

    setLoading(true);
    setError('');

    try {
      const response = await fetch('/api/proxy', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          userId: credentials.userId,
          password: credentials.password,
          page: pagination.page,
          limit: pagination.limit,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to fetch logs');
      }

      const data = await response.json();
      // API returns { logs: [...], pagination: {...} }
      const logsArray = (data.logs || []).map((log, index) => ({
        id: ((pagination.page - 1) * pagination.limit) + index + 1,
        title: log.file?.split('/').pop() || `Log ${index + 1}`,
        date: log.last_modified,
        status: 'Available',
        type: log.file?.split('.').pop() || 'log',
        description: `Size: ${log.size} bytes`,
        s3Url: log.download_url,
      }));
      setLogs(logsArray);

      // Update pagination info
      if (data.pagination) {
        setPagination(prev => ({
          ...prev,
          totalLogs: data.pagination.totalLogs,
          totalPages: data.pagination.totalPages,
        }));
      }
    } catch (err) {
      setError('Failed to load logs. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const goToPage = (newPage) => {
    if (newPage >= 1 && newPage <= pagination.totalPages) {
      setPagination(prev => ({ ...prev, page: newPage }));
    }
  };

  const handleDownload = async (s3Url, logId) => {
    try {
      // Use proxy to fetch S3 data
      const response = await fetch('/api/fetch-data', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          url: s3Url,
          userId: credentials.userId,
          password: credentials.password,
        }),
      });

      const parsedData = await response.json();

      onViewData({
        logId,
        s3Url,
        content: parsedData,
      });
    } catch (err) {
      setError('Failed to download data');
    }
  };

  const parseDelimitedText = (text) => {
    const lines = text.trim().split('\n');
    if (lines.length === 0) return [];

    const headers = lines[0].split(',').map(h => h.trim().replace(/"/g, ''));
    const rows = lines.slice(1).map(line => {
      const values = line.split(',').map(v => v.trim().replace(/"/g, ''));
      const row = {};
      headers.forEach((header, index) => {
        row[header] = values[index] || '';
      });
      return row;
    });

    return { headers, rows };
  };

  if (loading) {
    return <div className="loading">Loading logs...</div>;
  }

  if (error) {
    return (
      <div className="error-message">
        {error}
        <button onClick={fetchLogs} style={{ marginLeft: '10px' }}>
          Retry
        </button>
      </div>
    );
  }

  return (
    <div>
      {logs.length === 0 ? (
        <div className="no-logs">No logs available</div>
      ) : (
        <div className="logs-grid">
          {logs.map((log) => (
            <div key={log.id} className="log-card">
              <h3>{log.title || `Log #${log.id}`}</h3>
              <div className="log-details">
                <div className="log-detail">
                  <span>ID:</span>
                  <span>{log.id}</span>
                </div>
                <div className="log-detail">
                  <span>Date:</span>
                  <span>{formatDate(log.date)}</span>
                </div>
                <div className="log-detail">
                  <span>Status:</span>
                  <span>{log.status || 'Unknown'}</span>
                </div>
                {log.type && (
                  <div className="log-detail">
                    <span>Type:</span>
                    <span>{log.type}</span>
                  </div>
                )}
                {log.description && (
                  <div className="log-detail">
                    <span>Description:</span>
                    <span>{log.description}</span>
                  </div>
                )}
              </div>
              {log.s3Url && (
                <button
                  className="btn-download"
                  onClick={() => handleDownload(log.s3Url, log.id)}
                >
                  View Details
                </button>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Pagination Controls */}
      {pagination.totalPages > 1 && (
        <div className="pagination">
          <button 
            onClick={() => goToPage(1)} 
            disabled={pagination.page === 1}
            title="First page"
          >
            ««
          </button>
          <button 
            onClick={() => goToPage(pagination.page - 1)} 
            disabled={pagination.page === 1}
          >
            « Prev
          </button>
          <span className="page-info">
            Page {pagination.page} of {pagination.totalPages}
            <br/>
            <small>({pagination.totalLogs} total logs)</small>
          </span>
          <button 
            onClick={() => goToPage(pagination.page + 1)} 
            disabled={pagination.page === pagination.totalPages}
          >
            Next »
          </button>
          <button 
            onClick={() => goToPage(pagination.totalPages)} 
            disabled={pagination.page === pagination.totalPages}
            title="Last page"
          >
            »»
          </button>
        </div>
      )}
    </div>
  );
}

function formatDate(dateString) {
  if (!dateString) return 'N/A';
  const date = new Date(dateString);
  return date.toLocaleDateString() + ' ' + date.toLocaleTimeString();
}

export default LogViewer;
